// The pediatric GROWTH-CHART LMS dataset, loaded onto the curated-dataset framework
// (issue #860 Track B). Copies the mets.ts shape (meta + entries): import the envelope
// JSON (generated by scripts/gen-growth-charts.ts), validate it once with loadDataset(),
// and expose the per-metric ENTRIES, the dataset-level `meta` scalars, and a rebuilt
// metric→source→sex→rows map the pure math consumes. Identity is the metric `name`
// (nameStrategy) — one entry per metric. The registry lists this for the linter;
// lib/growth.ts is the pure LMS ↔ z ↔ percentile lookup over these entries. Pure — no
// DB, no network.

import rawCharts from "./data/growth-charts.json";
import { loadDataset } from "./loader";
import { nameStrategy } from "./matcher";
import type {
  GrowthChartEntry,
  GrowthChartsMeta,
  GrowthMetric,
  SexRows,
  Row,
} from "@/scripts/gen-growth-charts";

export type {
  GrowthChartEntry,
  GrowthChartsMeta,
  GrowthMetric,
  SexRows,
  Row,
} from "@/scripts/gen-growth-charts";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const growthChartsDataset = loadDataset<
  GrowthChartEntry,
  GrowthChartsMeta
>(rawCharts);

// Identity strategy: the metric `name` (case-folded). For the linter/harness — each
// entry carries a unique metric name, so identity resolves and an unknown metric refuses.
export const growthChartNameStrategy = nameStrategy;

// The per-metric entries (curated order) and the dataset-level scalars.
export const GROWTH_CHART_ENTRIES: GrowthChartEntry[] =
  growthChartsDataset.entries;
export const GROWTH_META: GrowthChartsMeta =
  growthChartsDataset.meta as GrowthChartsMeta;

// A metric→source→sex→rows map rebuilt from the entries, keyed by the EXACT metric name
// with only the present source keys (byte-for-byte, so the pure math's `CHARTS[metric]
// ?.[source]?.[sex]` behaves exactly as it did over the old `charts` map). One source of
// truth for the shape.
export const GROWTH_CHARTS_MAP: Record<
  string,
  Partial<Record<"who" | "cdc", SexRows>>
> = Object.fromEntries(
  GROWTH_CHART_ENTRIES.map((e) => {
    const sources: Partial<Record<"who" | "cdc", SexRows>> = {};
    if (e.who) sources.who = e.who;
    if (e.cdc) sources.cdc = e.cdc;
    return [e.name, sources];
  })
);

export type { Row as GrowthRow };
